import z from 'zod';

import { REQUEST_PARAMS } from '@/shared/descriptions';

import { coreRequestSchema, fetchShape } from './core';

const cliRequestHeadersSchema = z
  .array(
    z.string().superRefine((value, ctx) => {
      const separatorIndex = value.indexOf(':');

      if (separatorIndex === -1) {
        ctx.addIssue({
          code: 'custom',
          message: 'Headers must be in "Name: value" format',
        });
        return;
      }

      const name = value.slice(0, separatorIndex).trim();
      if (!name) {
        ctx.addIssue({
          code: 'custom',
          message: 'Header name must not be empty',
        });
      }
    })
  )
  .optional()
  .describe(REQUEST_PARAMS.headers)
  .transform(headers =>
    Object.fromEntries(
      headers?.map(header => {
        const separatorIndex = header.indexOf(':');
        const name = header.slice(0, separatorIndex).trim();
        const headerValue = header.slice(separatorIndex + 1).trimStart();

        return [name, headerValue];
      }) ?? []
    )
  );

export const cliRequestSchema = coreRequestSchema.extend({
  body: z.string().optional().describe(REQUEST_PARAMS.body),
  headers: cliRequestHeadersSchema,
});

export const cliFetchRequestSchema = cliRequestSchema.extend(fetchShape);
